class Solution:
    def zigzagTraversal(self, grid):
        seq = []
        for r in range(len(grid)):
            cols = list(range(len(grid[0]))) if r % 2 == 0 else list(range(len(grid[0]) - 1, -1, -1))
            for c in cols:
                seq.append(grid[r][c])
        return seq[0::2]

