class Solution:
    def zigzagTraversal(self, grid):
        m, n = len(grid), len(grid[0])
        result = []
        pos = 0
        for r in range(m):
            cols = range(n) if r % 2 == 0 else range(n - 1, -1, -1)
            for c in cols:
                if pos % 2 == 0:
                    result.append(grid[r][c])
                pos += 1
        return result

