var zigzagTraversal = function(grid) {
    const m = grid.length, n = grid[0].length;
    const result = [];
    let pos = 0;
    for (let r = 0; r < m; r++) {
        if (r % 2 === 0) {
            for (let c = 0; c < n; c++) {
                if (pos % 2 === 0) result.push(grid[r][c]);
                pos++;
            }
        } else {
            for (let c = n - 1; c >= 0; c--) {
                if (pos % 2 === 0) result.push(grid[r][c]);
                pos++;
            }
        }
    }
    return result;
};
